inline void negateOddsAndHalveEvens(std::vector<int> &x) {
    // OpenMP parallel for. Use static scheduling for balanced work.
    #pragma omp parallel for schedule(static)
    for (std::intptr_t i = 0; i < static_cast<std::intptr_t>(x.size()); ++i) {
