    bins.fill(0);

    // Each thread keeps a private copy of a small array.
    const std::size_t num_threads = omp_get_max_threads();
    std::vector<std::array<std::size_t, 26>> local_bins(num_threads);
    for (auto& arr : local_bins) arr.fill(0);

    // Parallel loop.  We use a static schedule to keep bound
    // on the amount of work per thread simple.
