    for (std::size_t i = 0; i < s.size(); ++i)
    {
        const std::size_t tid = omp_get_thread_num();
        const char* ptr   = s[i].c_str();     // first character
        const std::size_t index = static_cast<std::size_t>(ptr[0] - 'a');
        local_bins[tid][index] += 1;
