        size_t lcnt[4] = {0, 0, 0, 0};

        #pragma omp for schedule(static)
        for (std::size_t i = 0; i < x.size(); ++i) {
            const double val  = x[i];
            const double frac = val - (int)val;   // cheaper than std::fmod
            if      (frac < 0.25)  ++lcnt[0];
            else if (frac < 0.5)   ++lcnt[1];
            else if (frac < 0.75)  ++lcnt[2];
            else                   ++lcnt[3];
        }

        // Merge thread results into the global counters
        #pragma omp critical
        {
            for (int k = 0; k < 4; ++k) bins[k] += lcnt[k];
        }
