19_graph_shortest_path:
```cpp
#pragma once
#include <vector>
#include <limits>
#include <cstddef>
#include <cstring>

/* Return the length of the shortest path from source to dest in the undirected graph
 * defined by the adjacency matrix A (row‑major). The graph is assumed to be connected.
 *
 * Optimised for performance:
 *   - Avoids std::queue overhead by using a fixed‑size circular buffer.
 *   - Uses a std::vector<char> for the visited set (1 byte per flag).
 *   - Direct indexing into the flat adjacency matrix.
 *   - Special‑casing source == dest.
 */
inline int shortestPathLength(const std::vector<int>& A, size_t N, int source, int dest)
{
    if (source == dest) return 0;

    // visited flags (char == 0/1 is most compact)
    std::vector<char> visited(N, 0);
    // Allocate a simple circular buffer for the queue
    std::vector<int> q_buf(N);
    size_t q_head = 0, q_tail = 0;      // indices in the buffer

    visited[source] = 1;
    q_buf[q_tail++] = source;           // store vertex indices only

    std::vector<int> dist(N, -1);
    dist[source] = 0;

    while (q_head != q_tail) {
        const int cur = q_buf[q_head++];
        const int curDist = dist[cur];
        // Iterate over adjacency list (row of matrix)
        const int base = static_cast<int>(cur * N);
        for (int nxt = 0; nxt < static_cast<int>(N); ++nxt) {
            if (A[base + nxt] && !visited[nxt]) {
                visited[nxt] = 1;
                dist[nxt] = curDist + 1;
                if (nxt == dest) return dist[nxt];
                q_buf[q_tail++] = nxt;
            }
        }
    }

    return std::numeric_limits<int>::max(); // unreachable (shouldn't happen)
}
