/* Count the number of pixels in image with each grayscale intensity.
   The vector `image` is a grayscale image with values 0-255.
   Store the results in `bins`.
   Example:

   input: image=[2, 116, 201, 11, 92, 92, 201, 4, 2]
   output: [0, 0, 2, 0, 1, ...]
*/
void pixelCounts(std::vector<int> const& image, std::array<size_t, 256> &bins) {
    const size_t n = image.size();
    // initialise bins to zero (in case caller reused the array)
    for (size_t i = 0; i < bins.size(); ++i) bins[i] = 0;

    // Allocate per‑thread local bins
    const int nthreads = omp_get_max_threads();
    std::vector<std::array<size_t, 256>> localBins(nthreads);
    for (int t = 0; t < nthreads; ++t) {
        for (size_t i = 0; i < 256; ++i) localBins[t][i] = 0;
    }

    // Parallel loop with manual reduction
    #pragma omp parallel
    {
        int tid = omp_get_thread_num();
        const size_t chunk = (n + nthreads - 1) / nthreads;
        const size_t start = tid * chunk;
        const size_t end   = std::min(start + chunk, n);
        auto &bin = localBins[tid];

        for (size_t i = start; i < end; ++i) {
            // Assuming image values are in 0..255 as per contract
            ++bin[static_cast<unsigned char>(image[i])];
        }
    }

    // Merge per‑thread bins into the final result
    for (int t = 0; t < nthreads; ++t) {
        const auto &bin = localBins[t];
        for (size_t i = 0; i < 256; ++i) {
            bins[i] += bin[i];
        }
    }
}
