#pragma once
#include <vector>
#include <cstdint>
#include <algorithm>
#include <numeric>
#include <omp.h>

/*
 * Compute the inclusive prefix sum of a vector using a parallel
 * algorithm while preserving the exact semantics of std::inclusive_scan.
 *
 * The function is fully thread‑safe and works with the provided harness.
 */
inline void prefixSum(const std::vector<int64_t> &x, std::vector<int64_t> &output) {
    const std::size_t n = x.size();
    output.resize(n);
    if (n == 0) return;

    /* Work‑group size: roughly 512 elements per chunk, but OMP will distribute
     * the work anyway. */
    const std::size_t chunk = 512;

    /* First pass: compute partial sums for each chunk in parallel. */
    std::vector<int64_t> chunkSums((n + chunk - 1) / chunk);
#pragma omp parallel for schedule(static)
    for (std::size_t start = 0; start < n; start += chunk) {
        std::size_t end = std::min(start + chunk, n);
        int64_t sum = 0;
        for (std::size_t i = start; i < end; ++i) {
            sum += x[i];
            output[i] = sum;
        }
        chunkSums[start / chunk] = sum;
    }

    /* Second pass: compute prefix sum of chunkSums in a single thread
     * (the size is small, serial computation is trivial). */
    std::vector<int64_t> chunkPrefixes(chunkSums.size());
    std::partial_sum(chunkSums.begin(), chunkSums.end(), chunkPrefixes.begin());

    /* Third pass: add the offset of previous chunks to each element. */
#pragma omp parallel for schedule(static)
    for (std::size_t start = 0; start < n; start += chunk) {
        std::size_t idx = start / chunk;
        int64_t offset = idx > 0 ? chunkPrefixes[idx - 1] : 0;
        for (std::size_t i = start; i < std::min(start + chunk, n); ++i) {
            output[i] += offset;
        }
    }
}
