```cpp
#pragma once
#include <vector>
#include <algorithm>
#include <cstddef>
#include <cstdint>

/*      
 * Return the number of vertices in the largest component of the graph
 * defined by the adjacency matrix A (row-major NxN).  
 *
 * The implementation uses an iterative depth‑first search with a
 * pre‑allocated stack and a byte‑array for visited flags.  All
 * operations are cache friendly; recursion is eliminated to avoid
 * function‑call overhead and large call stacks.  The code relies only
 * on the standard library and is fully compatible with gcc ‑O2 ‑fopenmp,
 * although no OpenMP parallelism is used because the problem is
 * inherently sequential when a global visited array is required.
 */

inline void iterative_dfs(const int* __restrict A,
                          size_t N,
                          int start,
                          std::vector<uint8_t>& visited,
                          int* __restrict count)
{
    // Simple manual stack – capacity never exceeds N.
    std::vector<int> stack;
    stack.reserve(N);
    stack.push_back(start);

    while (!stack.empty()) {
        int node = stack.back();
        stack.pop_back();

        if (visited[node]) continue;
        visited[node] = 1;
        ++(*count);

        // Iterate over adjacency row of 'node'.
        const int* row = A + node * N;
        for (int i = 0; i < static_cast<int>(N); ++i) {
            // Only push if there is an edge and the vertex hasn't been visited.
            if (row[i] == 1 && !visited[i]) {
                stack.push_back(i);
            }
        }
    }
}

int largestComponent(const std::vector<int>& A, size_t N)
{
    // Use a byte‑array for visited flags for better cache behaviour.
    std::vector<uint8_t> visited(N, 0);
    int maxCount = 0;

    const int* data = A.data(); // pointer to the underlying array

    for (int i = 0; i < static_cast<int>(N); ++i) {
        if (!visited[i]) {
            int cnt = 0;
            iterative_dfs(data, N, i, visited, &cnt);
            if (cnt > maxCount) maxCount = cnt;
        }
    }
    return maxCount;
}
