/* A persistent COO representation of a sparse matrix. */
struct COOElement {
    std::size_t row, column;
    double value;
};

/* Full LU factorisation of a sparse square matrix A in COO format.
 * L and U are stored as flat N×N row‑major vectors.
 *
 * The algorithm follows the textbook Doolittle method with
 * an explicit construction of the dense matrix from the sparse
 * single‑value entries.  This is equivalent to the original
 * reference implementation but uses a flat array for speed.
 */
inline void luFactorize(const std::vector<COOElement> &A,
                        std::vector<double> &L,
                        std::vector<double> &U,
                        std::size_t N)
{
    /* Allocate 1D dense matrix (for A and temporary use). */
    std::vector<double> dense(A.size() > 0 ? N * N : 0, 0.0);

    /* Populate the dense matrix from COO. */
    for (const auto &e : A) {
        dense[e.row * N + e.column] = e.value;
    }

    /* Ensure L and U are sized correctly and zeroed. */
    L.assign(N * N, 0.0);
    U.assign(N * N, 0.0);

    /* Classic Doolittle LU factorisation.  No parallelisation is
     * possible due to the data dependencies across rows. */
    for (std::size_t i = 0; i < N; ++i) {
        /* U‑row i */
        for (std::size_t j = i; j < N; ++j) {
            std::size_t idx = i * N + j;
            double tmp = dense[idx];
            for (std::size_t k = 0; k < i; ++k)
                tmp -= L[idx - (i - k) * N] * U[k * N + j];
            U[idx] = tmp;
        }

        /* L‑column i (excluding diagonal) */
        for (std::size_t j = i + 1; j < N; ++j) {
            std::size_t idx = j * N + i;
            double tmp = dense[idx];
            for (std::size_t k = 0; k < i; ++k)
                tmp -= L[j * N + k] * U[k * N + i];
            L[idx] = tmp / U[i * N + i];
        }

        /* Unit diagonal for L */
        L[i * N + i] = 1.0;
    }
}
