inline void binsBy10Count(std::vector<double> const& x, std::array<std::size_t, 10>& bins) noexcept
{
    // zero the output array (if it may be reused)
    for (auto& v : bins) v = 0;

    const std::size_t n = x.size();
    const std::size_t nthreads = omp_get_max_threads();
    // per‑thread local bins.  Memory layout: thread*n_bins + bin
    std::vector<std::size_t> local(nthreads * 10, 0);

    #pragma omp parallel
    {
        const std::size_t tid = omp_get_thread_num();
        std::size_t* const local_bins = &local[tid * 10];

        // do the work in chunks, automatically scheduled by OpenMP
        #pragma omp for schedule(static, 1e5)
        for (std::size_t i = 0; i < n; ++i)
        {
            // fast floor division by 10 for non‑negative doubles
            std::size_t bin = static_cast<std::size_t>(x[i] / 10.0);
            // clamp to 0‑9; 100/10 would give 10
            if (bin >= 10) bin = 9;
            ++local_bins[bin];
        }
    } // end of parallel region

    // reduce per‑thread bins into the output array
    for (std::size_t th = 0; th < nthreads; ++th)
        for (std::size_t b = 0; b < 10; ++b)
