/* Return the distance between the closest two elements in the vector x.
   Example:
   input: [7, 3, 9, 12, 31, 1]
   output: 2
*/
double closestPair(std::vector<double> const& x) {
    // At least two elements are required; otherwise the distance is undefined.
    if (x.size() < 2) return 0.0;

    // Make a local copy that can be sorted without modifying the original data.
    std::vector<double> arr(x.begin(), x.end());
    std::sort(arr.begin(), arr.end());

    // The minimum distance is guaranteed to be found among neighbors in sorted order.
    double minDist = std::numeric_limits<double>::max();

    // Parallel scan with reduction. Each thread computes the minimum in its chunk
    // and the final value is the global minimum.
#pragma omp parallel for reduction(min : minDist)
    for (std::size_t i = 0; i + 1 < arr.size(); ++i) {
        double d = std::abs(arr[i + 1] - arr[i]); // all elements are sorted
        if (d < minDist) {
            minDist = d;
        }
    }

    return minDist;
}
