#if !defined(M_PI)
 #define M_PI 3.14159265358979323846
#endif

// Optimised iterative radix‑2 Cooley‑Tukey FFT
// Assumes output.size() is a power of two
void fft(const std::vector<std::complex<double>>& x, std::vector<std::complex<double>>& output)
{
    const std::size_t N = x.size();
    output = x;

    // Bit‑reversal permutation
    std::size_t rev = 0;
    for (std::size_t i = 0; i < N; ++i) {
        if (i < rev) std::swap(output[i], output[rev]);

        std::size_t mask = N >> 1;
        while (rev & mask) {
            rev ^= mask;
            mask >>= 1;
        }
        rev ^= mask;
    }

    // Pre‑compute twiddle factors
    std::vector<std::complex<double>> roots(N / 2);
    for (std::size_t i = 0; i < N / 2; ++i) {
        double angle = -2.0 * M_PI * i / static_cast<double>(N);
        roots[i] = std::exp(std::complex<double>(0.0, angle));
    }

    // FFT stages
    for (std::size_t span = 2; span <= N; span <<= 1)
    {
        const std::size_t half = span >> 1;
        const std::size_t step  = N / span;

        // Parallelise the outer loop (over block starts)
        #pragma omp parallel for schedule(static)
        for (std::size_t start = 0; start < N; start += span)
        {
            for (std::size_t j = 0; j < half; ++j)
            {
                const std::size_t idx1 = start + j;
                const std::size_t idx2 = idx1 + half;
                const std::complex<double> t = roots[j * step] * output[idx2];
                output[idx2] = output[idx1] - t;
                output[idx1] += t;
            }
        }
    }
}
