 * z is a dense vector (pre‑allocated to the required size).
 *
 * The original implementation merged the two input vectors while
 * traversing them in sorted order.  For performance we replace this
 * with two independent parallel loops: one for the contribution from
 * `x` and one from `y`.  Each loop updates `z[idx]` atomically to avoid
 * data races when the same index appears in both vectors.
 *
 * This approach preserves the exact numerical result of the original
 * algorithm while exploiting multi‑threading on an 8‑thread x86‑64
 * machine with `gcc -O2 -fopenmp`.
 */
inline void sparseAxpy(double alpha,
                       const std::vector<Element>& x,
                       const std::vector<Element>& y,
                       std::vector<double>& z)
{
    const std::size_t nx = x.size();
    const std::size_t ny = y.size();

    /* Update contributions from vector x */
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < nx; ++i) {
        const std::size_t idx = x[i].index;
        const double val = alpha * x[i].value;
        #pragma omp atomic
        z[idx] += val;
    }

    /* Update contributions from vector y */
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < ny; ++i) {
        const std::size_t idx = y[i].index;
        const double val = y[i].value;
        #pragma omp atomic
        z[idx] += val;
    }
