/* Compute one iteration of a 3-point 1D Jacobi stencil on `input` and write the
   results to `output`.  The stencil average is computed as
   output[i] = (input[i-1] + input[i] + input[i+1]) / 3,
   with out-of-bounds indices treated as zero.  This implementation is
   thread‑safe, fully parallelized with OpenMP, and keeps all floating‑point
   semantics identical to the naïve reference implementation. */
inline void jacobi1D(std::vector<double> const& input,
                     std::vector<double> &output) noexcept
{
    const std::size_t n = input.size();
    if (n == 0) return;

    /* Ensure output is the correct size */
    if (output.size() != n) output.resize(n);

    /* Handle the first element (no left neighbor) */
    output[0] = (input[0] + (n > 1 ? input[1] : 0.0)) / 3.0;

    /* Handle the last element (no right neighbor) */
    output[n-1] = ( (n>1? input[n-2] : 0.0) + input[n-1] ) / 3.0;

    /* Parallel loop for the interior elements */
#pragma omp parallel for schedule(static)
    for (std::size_t i = 1; i < n-1; ++i)
    {
        output[i] = (input[i-1] + input[i] + input[i+1]) / 3.0;
    }
}
