```cpp
#pragma once
#include <vector>
#include <numeric>   // for std::iota
#include <cstddef>

/* Count the number of connected components in the undirected graph
   defined by the adjacency matrix A. A is an NxN adjacency matrix
   stored in row-major order. The matrix represents an undirected
   graph, so A[i*N + j] == A[j*N + i] and the diagonal is 0.
   Complexity:   O(N²) time, O(N) extra memory
   Implementation uses a union‑find data structure with path
   compression and union by rank.  This avoids recursive DFS and is
   much cheaper for dense graphs.
*/
int componentCount(const std::vector<int>& A, size_t N)
{
    // Union‑find data structures
    std::vector<int> parent(N);
    std::vector<int> rank(N, 0);  // rank (approx depth)
    std::iota(parent.begin(), parent.end(), 0);

    auto findRoot = [&](int x) -> int {
        while (parent[x] != x) {
            parent[x] = parent[parent[x]];  // path halving
            x = parent[x];
        }
        return x;
    };

    auto unite = [&](int a, int b) {
        int ra = findRoot(a);
        int rb = findRoot(b);
        if (ra == rb) return;
        if (rank[ra] < rank[rb]) std::swap(ra, rb);
        parent[rb] = ra;
        if (rank[ra] == rank[rb]) ++rank[ra];
    };

    const int* data = A.data();

    // Scan only upper triangle (i < j), the graph is undirected.
    for (size_t i = 0; i < N; ++i) {
        size_t rowStart = i * N;
        for (size_t j = i + 1; j < N; ++j) {
            if (data[rowStart + j] == 1) {
                unite(static_cast<int>(i), static_cast<int>(j));
            }
        }
    }

    // Count unique roots
    int components = 0;
    for (int i = 0; i < static_cast<int>(N); ++i) {
        if (parent[i] == i) ++components;
    }
    return components;
}
