#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <cstdint>
#include <algorithm>
#include <omp.h>

/*
   Optimised iterative radix‑2 Cooley‑Tukey FFT.
   It keeps the exact mathematical semantics of the original
   reference implementation (real/imag exact within round‑off).
   Parallelisation is performed on the outer butterfly stages
   using OpenMP; the bit‑reversal is precomputed to avoid
   run‑time branching.
*/
static inline void fft(std::vector<std::complex<double>> const& x,
                       std::vector<double>& r,
                       std::vector<double>& i)
{
    const size_t N = x.size();
    if (N == 0) return;

    /* ---------- 1. Bit‑reverse indices once -------------------------------- */
    static std::vector<size_t> rev;
    static size_t lastN = 0;
    if (lastN != N) {
        rev.resize(N);
        const size_t bits = static_cast<size_t>(std::log2(N));
        for (size_t j = 0; j < N; ++j) {
            size_t x = j, y = 0;
            for (size_t k = 0; k < bits; ++k) {
                y = (y << 1) | (x & 1u);
                x >>= 1;
            }
            rev[j] = y;
        }
        lastN = N;
    }

    /* ---------- 2. Create working copy and reorder -------------------------------- */
    std::vector<std::complex<double>> a(N);
    #pragma omp parallel for schedule(static)
    for (size_t j = 0; j < N; ++j) a[rev[j]] = x[j];

    /* ---------- 3. Pre‑compute twiddle roots -------------------------------- */
    const double PI = 3.141592653589793238462643383279502884L;
    std::vector<std::complex<double>> roots(N / 2);
    for (size_t k = 0; k < N / 2; ++k)
        roots[k] = std::exp(-1i * PI * static_cast<double>(k) / static_cast<double>(N));

    /* ---------- 4. Iterative FFT stages -------------------------------- */
    size_t half = 1;
    while (half < N) {
        size_t step = half << 1;
        /* for each butterfly group compute independent on different cores */
        #pragma omp parallel for schedule(static)
        for (size_t i0 = 0; i0 < N; i0 += step) {
            for (size_t j = 0; j < half; ++j) {
                const size_t idx1 = i0 + j;
                const size_t idx2 = idx1 + half;
                const std::complex<double> t = a[idx2] * roots[(N / step) * j];
                a[idx2] = a[idx1] - t;
                a[idx1] += t;
            }
        }
        half = step;
    }

    /* ---------- 5. Split into real / imaginary -------------------------------- */
    #pragma omp parallel for schedule(static)
    for (size_t j = 0; j < N; ++j) {
        r[j] = a[j].real();
        i[j] = a[j].imag();
    }
}
