#pragma once
#include <vector>
#include <algorithm>
#include <cmath>
#include <cstddef>

struct COOElement {
    std::size_t row, column;
    double      value;
};

inline double std_abs(double v) { return v < 0 ? -v : v; }

/* Solve the sparse linear system Ax=b for x.
   A is a sparse NxN matrix in COO format. x and b are dense vectors with N elements.
   Example:
      input: A=[{0,0,1}, {0,1,1}, {1,1,-2}] b=[1,4]
      output: x=[3,-2]
*/
void solveLinearSystem(std::vector<COOElement> const& A,
                       std::vector<double>  const& b,
                       std::vector<double>        & x,
                       std::size_t                    N)
{
    /* 1. Build a dense matrix in a single 1‑D array for maximum cache friendliness.
         Avoid std::vector<std::vector<...>> to eliminate indirection.
    */
    std::vector<double> mat(N * N, 0.0);
    for (auto const& e : A)
        mat[e.row * N + e.column] = e.value;

    /* 2. Copy RHS vector */
    std::vector<double> rhs = b;

    /* 3. Gaussian elimination with partial pivoting */
    for (std::size_t i = 0; i < N; ++i) {
        /* find pivot row */
        std::size_t maxRow = i;
        double      maxVal = std_abs(mat[i * N + i]);

        for (std::size_t k = i + 1; k < N; ++k) {
            double val = std_abs(mat[k * N + i]);
            if (val > maxVal) { maxVal = val; maxRow = k; }
        }

        /* swap rows i and maxRow in matrix */
        if (maxRow != i) {
            for (std::size_t j = i; j < N; ++j)
                std::swap(mat[i * N + j], mat[maxRow * N + j]);
            std::swap(rhs[i], rhs[maxRow]);
        }

        /* pivot element (must not be zero in exact arithmetic) */
        double pivot = mat[i * N + i];

        /* eliminate rows below pivot */
        for (std::size_t k = i + 1; k < N; ++k) {
            double factor = -mat[k * N + i] / pivot;
            for (std::size_t j = i; j < N; ++j) {
                if (j == i)
                    mat[k * N + j] = 0.0;
                else
                    mat[k * N + j] += factor * mat[i * N + j];
            }
            rhs[k] += factor * rhs[i];
        }
    }

    /* 4. Back substitution */
    x.resize(N);
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        double sum = rhs[i];
        for (int j = static_cast<int>(i) + 1; j < static_cast<int>(N); ++j)
            sum -= mat[i * N + j] * x[j];
        x[i] = sum / mat[i * N + i];
    }
}
