double convexHullPerimeter(const std::vector<Point>& points){
    const std::size_t n = points.size();
    if(n<3) return 0.0;

    // local copy for sorting
    std::vector<Point> sorted(points);
    std::sort(sorted.begin(), sorted.end(),
              [](const Point& A,const Point& B){
                  return A.x<B.x || (A.x==B.x && A.y<B.y);
              });

    // hull array (max 2n, reused for both halves)
    std::vector<Point> hull(2*n);
    std::size_t k=0;

    // lower hull
    for(std::size_t i=0;i<n;i++){
        while(k>=2 && cross(hull[k-2], hull[k-1], sorted[i])<=0) --k;
        hull[k++]=sorted[i];
    }

    // upper hull
    for(std::size_t i=n-1;i>0;i--){
        while(k>= (std::size_t) (k- (i+1) > 0 ? k-(i+1) : 1) && cross(hull[k-2], hull[k-1], sorted[i-1])<=0) --k;
        hull[k++]=sorted[i-1];
    }

    // last point duplicates first; shrink
    hull.resize(k-1);

    // compute perimeter in parallel (reduction)
    double perimeter=0.0;
    #pragma omp parallel for reduction(+:perimeter) schedule(static)
    for(std::size_t i=0;i<hull.size();i++){
        const std::size_t j = (i+1==hull.size()?0:i+1);
        perimeter += dist(hull[i], hull[j]);
    }
    return perimeter;
}
