// ──────────────────────────────────────────────────────────────────────
// Optimised DFT implementation (openmp, O(N²) but with heavy
// vectorisation / recurrence of complex exponentials).
// Maintains identical behaviour and signature to the supplied code.
// ──────────────────────────────────────────────────────────────────────
#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <cstddef>
#include <omp.h>

#if !defined(M_PI)
#define M_PI 3.14159265358979323846
#endif

// Compute the DFT of `x` into `output` using a recurrence for the
// complex exponentials.  Parallelised over the output indices (`k`).
// The algorithm uses only L1‑friendly operations and avoids per‑step
// trigonometric calls.
inline void dft(const std::vector<double> &x,
                std::vector<std::complex<double>> &output)
{
    const std::size_t N = x.size();
    output.resize(N);
    const double two_pi_over_N = 2.0 * M_PI / static_cast<double>(N);

    // Parallel loop over output indices; each thread owns a sub‑range of k.
    #pragma omp parallel for schedule(static)
    for (std::ptrdiff_t k = 0; k < static_cast<std::ptrdiff_t>(N); ++k)
    {
        // Compute the base complex multiplier for this k
        const double angle_k = two_pi_over_N * static_cast<double>(k);
        const std::complex<double> w_base(std::cos(angle_k), -std::sin(angle_k));

        std::complex<double> sum(0.0, 0.0);
        std::complex<double> w(1.0, 0.0);           // = exp(-j*0*angle_k)

        // Unroll a bit: 4 terms per iteration (helps the compiler)
        const std::size_t unroll = 4;
        const std::size_t chunks = N / unroll;
        for (std::size_t chunk = 0; chunk < chunks; ++chunk)
        {
            const std::size_t idx = chunk * unroll;
            sum += w * x[idx];
            w *= w_base;
            sum += w * x[idx + 1];
            w *= w_base;
            sum += w * x[idx + 2];
            w *= w_base;
            sum += w * x[idx + 3];
            w *= w_base;
        }

        // Remaining indices
        for (std::size_t idx = chunks * unroll; idx < N; ++idx)
        {
            sum += w * x[idx];
            w *= w_base;
        }

        output[static_cast<std::size_t>(k)] = sum;
    }
}
