#pragma once
#include <vector>
#include <cstring>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

/*
 * Compute the matrix multiplication Y = A * X.
 * A : MxK sparse matrix in COO format
 * X : KxN sparse matrix in COO format
 * Y : dense MxN matrix in row-major (output)
 *
 * The implementation groups the non‑zeros of X by their row index
 * and then processes the non‑zeros of A in parallel.  Each thread
 * writes into its own private output buffer to avoid atomic
 * operations, and the private buffers are summed at the end.
 */
void spmm(std::vector<COOElement> const& A,
          std::vector<COOElement> const& X,
          std::vector<double> &Y,
          size_t M, size_t K, size_t N)
{
    /* 1. Prepare column‑wise buckets for X  */
    std::vector<std::vector<COOElement>> x_by_row(K);
    for (auto const& e : X) {
        x_by_row[e.row].push_back(e);
    }

    /* 2. Allocate per‑thread private output buffers  */
    int nthreads = omp_get_max_threads();
    std::vector<double*> localY(nthreads);
    size_t MN = M * N;
    for (int t = 0; t < nthreads; ++t) {
        localY[t] = static_cast<double*>(aligned_alloc(64, MN * sizeof(double)));
        memset(localY[t], 0, MN * sizeof(double));
    }

    /* 3. Parallel accumulation over non‑zeros of A */
    #pragma omp parallel for schedule(dynamic)
    for (size_t idx = 0; idx < A.size(); ++idx) {
        int t = omp_get_thread_num();
        auto const& a = A[idx];
        if (a.column >= K)   // guard against malformed input
            continue;
        auto const& bucket = x_by_row[a.column];
        double* ybuf = localY[t];
        for (auto const& x : bucket) {
            ybuf[a.row * N + x.column] += a.value * x.value;
        }
    }

    /* 4. Reduce thread buffers into the final result */
    Y.resize(MN);
    for (size_t i = 0; i < MN; ++i) {
        double sum = 0.0;
        for (int t = 0; t < nthreads; ++t)
            sum += localY[t][i];
        Y[i] = sum;
    }

    /* 5. Free private buffers */
    for (int t = 0; t < nthreads; ++t)
        free(localY[t]);
}
