#pragma once
#include <vector>
#include <algorithm>
#include <cstddef>

struct Point {
    double x, y;
};

static inline double cross(const Point& a, const Point& b, const Point& c) noexcept
{
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

void convexHull(const std::vector<Point>& points, std::vector<Point>& hull)
{
    const std::size_t n = points.size();
    if (n < 3) {                     // A polygon needs at least 3 points
        hull.assign(points.begin(), points.end());
        return;
    }

    // Make a sorted copy – sorting dominates the time cost
    std::vector<Point> sorted = points;
    sorted.resize(n); // preserve capacity
    std::sort(sorted.begin(), sorted.end(),
              [](const Point& a, const Point& b) noexcept {
                  return (a.x < b.x) || (a.x == b.x && a.y < b.y);
              });

    // Reserve maximum possible size (upper + lower hull)
    std::vector<Point> stack;
    stack.reserve(2 * n);

    // Build lower hull
    for (std::size_t i = 0; i < n; ++i) {
        while (stack.size() >= 2 &&
               cross(stack[stack.size() - 2], stack.back(), sorted[i]) <= 0.0)
            stack.pop_back();
        stack.push_back(sorted[i]);
    }

    // Build upper hull – skip the last point because it is already in lower hull
    const std::size_t t = stack.size() + 1;
    for (std::size_t i = n; i > 1; --i) {
        while (stack.size() >= t &&
               cross(stack[stack.size() - 2], stack.back(), sorted[i - 2]) <= 0.0)
            stack.pop_back();
        stack.push_back(sorted[i - 2]);
    }

    // The last point of the upper hull is the same as the first point of the lower hull
    stack.pop_back();

    hull = std::move(stack);
}
