/* Multiply the MxN matrix A (row-major) by the vector x.
 * Result is stored in y (size M). All arguments are passed by reference.
 * The function preserves the exact numerical result of the naïve implementation.
 */
inline void gemv(const std::vector<double>& A,
                 const std::vector<double>& x,
                 std::vector<double>& y,
                 size_t M, size_t N)
{
    // Ensure dimensions are consistent
    if (y.size() < M || A.size() < M * N || x.size() < N) return;

    // Use raw pointers for speed – the compiler will inline the bound checks.
    const double* restrict a = A.data();
    const double* restrict vx = x.data();
    double* restrict vy = y.data();

    // Parallelize outer loop.  A static schedule is sufficient for regular work.
    #pragma omp parallel for schedule(static, 64)
    for (size_t i = 0; i < M; ++i)
    {
        const size_t offset = i * N;
        double sum = 0.0;
        // Inner loop unrolled by a factor of 4 (size_t is hopefully 64‑bit).
        const size_t limit = N & ~size_t(3);   // floor(N/4)*4
        size_t j = 0;
        for (; j < limit; j += 4)
        {
            sum += a[offset + j]   * vx[j];
            sum += a[offset + j+1] * vx[j+1];
            sum += a[offset + j+2] * vx[j+2];
            sum += a[offset + j+3] * vx[j+3];
        }
        for (; j < N; ++j) {          // Handle leftovers
            sum += a[offset + j] * vx[j];
        }
        vy[i] = sum;
    }
}
