/*
   Parallel, branch‑eliminated 5‑point Jacobi stencil.
   `input` and `output` are stored in row‑major order, size N×N.
*/
void jacobi2D(std::vector<double> const& input, std::vector<double> &output, size_t N) {
    // Padding for boundary handling (index shift +1)
    const size_t P = N + 2;                  // padded dimension
    std::vector<double> padded(P * P, 0.0);   // zero‑initialised

    // Copy input into padded array at offset (1,1)
    for (size_t i = 0; i < N; ++i) {
        const size_t in_off  = i * N;
        const size_t pad_off = (i + 1) * P + 1;
        std::copy_n(input.data() + in_off, N, padded.data() + pad_off);
    }

    // Reference to padded array for easier access
    const double* const pad = padded.data();
    double* out = output.data();

    // Perform the stencil row‑by‑row in parallel
    #pragma omp parallel for schedule(static)
    for (int ii = 0; ii < static_cast<int>(N); ++ii) {
        const int i = ii;                   // current row
        const int base = i * N;             // base index for output
        const int pi = i + 1;               // padded row index

        for (int j = 0; j < static_cast<int>(N); ++j) {
            const int pj = j + 1;           // padded column index
            const size_t idx = base + j;    // linear index in output

            // direct neighbour access without branches
            double s = pad[pi * P + pj]                  // center
                     + pad[(pi - 1) * P + pj]            // north
                     + pad[(pi + 1) * P + pj]            // south
                     + pad[pi * P + (pj - 1)]            // west
                     + pad[pi * P + (pj + 1)];           // east

            out[idx] = s / 5.0;
        }
    }
}
