/*
 * Replace the i-th element of the vector `x` with the minimum value from
 * indices 0 through i.
 * Example:
 *   input : [8, 6, -1, 7, 3, 4, 4]
 *   output: [8, 6, -1, -1, -1, -1, -1]
 *   input : [5, 4, 6, 4, 3, 6, 1, 1]
 *   output: [5, 4, 4, 4, 3, 3, 1, 1]
 *
 * The implementation below is intentionally simple and relies on a
 * single-pass loop that can be trivially parallelized with OpenMP.
 * The original algorithm performed an inclusive scan with a custom
 * binary operation.  The behaviour is equivalent to
 *
 *   for (size_t i = 0; i < x.size(); ++i)
 *       x[i] = std::min(x[i], x[i-1]); // with proper initial value
 *
 * which we implement directly.  Parallelization is achieved by recursively
 * computing partial minima for subranges and then merging the results.
 */
void partialMinimums(std::vector<float> &x) {
    const size_t n = x.size();
    if (n == 0) return;

    /* If the vector fits comfortably into cache we simply run a serial loop. */
    if (n <= 8192) {
        float curMin = std::numeric_limits<float>::max();
        for (size_t i = 0; i < n; ++i) {
            curMin = std::min(curMin, x[i]);
            x[i] = curMin;
        }
        return;
    }

    /* For larger vectors we compute partial minima in parallel.
     * We use a two-pass approach:
     *
     *   1. Each thread processes a block of the array, computing the
     *      minimum of its block and writing the result into a
     *      per‑thread vector `block_mins`.
     *   2. We then perform a serial pass over `block_mins` to obtain
     *      the running minimum up to the start of each block.
     *   3. Finally each thread revisits its block and updates the
     *      values by merging the block's local minimum with the
     *      previous global minimum.
     */
    const int nthreads = omp_get_max_threads();
    std::vector<float> block_mins(nthreads, std::numeric_limits<float>::max());

    /* First pass: compute local minima for each block. */
    #pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        const int blockSize = (n + nthreads - 1) / nthreads;
        const int start = tid * blockSize;
        const int end   = std::min(start + blockSize, static_cast<int>(n));

        float localMin = std::numeric_limits<float>::max();
        for (int i = start; i < end; ++i) {
            localMin = std::min(localMin, x[i]);
            x[i] = localMin;  // temporarily store local min for this block
        }
        block_mins[tid] = localMin;
    }

    /* Second pass: compute cumulative minima up to each block start. */
    std::vector<float> cumMin(nthreads, std::numeric_limits<float>::max());
    float cumulative = std::numeric_limits<float>::max();
    for (int i = 0; i < nthreads; ++i) {
        cumulative = std::min(cumulative, block_mins[i]);
        cumMin[i] = cumulative;
    }

    /* Third pass: merge the cumulative minima with each block. */
    #pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        const int blockSize = (n + nthreads - 1) / nthreads;
        const int start = tid * blockSize;
        const int end   = std::min(start + blockSize, static_cast<int>(n));

        float prevMin = cumMin[tid];
        for (int i = start; i < end; ++i) {
            prevMin = std::min(prevMin, x[i]);  // x[i] holds local min
            x[i] = prevMin;
        }
    }
}
