/*
 * Find the k-th smallest element of the vector `x`.
 *  
 * Example:
 *
 *   input:  x = [1, 7, 6, 0, 2, 2, 10, 6], k = 4
 *   output: 6
 *
 * The function performs a copy of `x` (to preserve the original
 * vector), then uses `std::nth_element` to find the value that
 * would appear at position `k-1` in a fully sorted sequence.
 * This gives the same behaviour as sorting the whole vector but
 * runs in linear time on average.
 */
int findKthSmallest(const std::vector<int>& x, int k)
{
    // Make a copy to avoid modifying the caller's vector
    std::vector<int> x_copy = x;

    // Validate k
    if (k < 1 || k > static_cast<int>(x_copy.size())) {
        throw std::out_of_range("k is out of bounds");
    }

    // Place the k-1 element in its final sorted position
    std::nth_element(x_copy.begin(), x_copy.begin() + (k - 1), x_copy.end());

    // The value at index k-1 is the k-th smallest
    return x_copy[k - 1];
}
