#pragma once
#include <vector>
#include <omp.h>

/* Solve the linear system Ax=b for x.
   A is an NxN matrix in row-major. x and b have N elements.
   Example:

   input: A=[[1,4,2], [1,2,3], [2,1,3]] b=[11, 11, 13]
   output: x=[3, 1, 2]
*/
inline void solveLinearSystem(const std::vector<double> &A,
                              const std::vector<double> &b,
                              std::vector<double> &x,
                              size_t N)
{
    // Copy input to avoid modifying originals
    std::vector<double> Acopy(A);
    std::vector<double> bcopy(b);

    // Gaussian elimination with OpenMP parallelism for inner loops
    for (size_t i = 0; i < N - 1; ++i) {
        const double pivot = Acopy[i * N + i];
        if (pivot == 0.0) return;   // singular matrix – keep original behaviour

        #pragma omp parallel for schedule(static)
        for (size_t j = i + 1; j < N; ++j) {
            const double factor = Acopy[j * N + i] / pivot;
            double *rowj = &Acopy[j * N];
            const double *rowi = &Acopy[i * N];
            for (size_t k = i; k < N; ++k) {
                rowj[k] -= factor * rowi[k];
            }
            bcopy[j] -= factor * bcopy[i];
        }
    }

    // Back substitution – serial (no gain from parallelisation here)
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        double sum = 0.0;
        const double *rowi = &Acopy[i * N];
        for (size_t j = i + 1; j < N; ++j) {
            sum += rowi[j] * x[j];
        }
        x[i] = (bcopy[i] - sum) / Acopy[i * N + i];
    }
}
