//---------------------------------------------------------------------------
// In-place FFT / inverse FFT (Cooley–Tukey)
// No external dependencies beyond the standard library and OpenMP
//---------------------------------------------------------------------------
namespace detail {

// returns the next power of two >= x
inline std::size_t next_power_of_two(std::size_t x) {
    if (x == 0) return 1;
    return 1ULL << (64 - __builtin_clzll(x - 1));
}

// pre‑compute twiddle factors for a given size
inline std::vector<std::complex<double>> twiddles(std::size_t n) {
    std::vector<std::complex<double>> w(n / 2);
    const double pi = std::acos(-1.0);
    for (std::size_t i = 0; i < n / 2; ++i) {
        double angle = -2.0 * pi * i / static_cast<double>(n);
        w[i] = std::complex<double>(std::cos(angle), std::sin(angle));
    }
    return w;
}

// in‑place bit‑reversal reordering
inline void bit_reverse(std::vector<std::complex<double>>& a) {
    const std::size_t n = a.size();
    std::size_t j = 0;
    for (std::size_t i = 0; i < n; ++i) {
        if (i < j) std::swap(a[i], a[j]);
        std::size_t m = n >> 1;
        while (j >= m && m) {
            j -= m;
            m >>= 1;
        }
        j += m;
    }
}

// butterfly kernel executed in parallel (OpenMP)
inline void fft_stage(std::vector<std::complex<double>>& a,
                      const std::vector<std::complex<double>>& w,
                      std::size_t step, std::size_t stride)
{
    const std::size_t n = a.size();
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < n; i += step * 2) {
        for (std::size_t j = 0; j < stride; ++j) {
            std::complex<double> x = a[i + j];
            std::complex<double> y = a[i + j + stride] * w[j];
            a[i + j] = x + y;
            a[i + j + stride] = x - y;
        }
    }
}

} // namespace detail

//---------------------------------------------------------------------------
// Public API
//---------------------------------------------------------------------------

inline void fft_helper(std::vector<std::complex<double>>& x) {
    const std::size_t n = x.size();
    if (n <= 1) return;

    // Bit‑reversal reordering
    detail::bit_reverse(x);

    // Iterative Cooley–Tukey
    std::size_t half = 1;
    while (half < n) {
        std::size_t full = half << 1;
        std::size_t stride = n / full;
        auto w = detail::twiddles(full);
        detail::fft_stage(x, w, full, half);
        half = full;
    }
}

inline void ifft(std::vector<std::complex<double>>& x) {
    // Conjugate, forward FFT, conjugate again, then scale
    for (auto& v : x) v = std::conj(v);
    fft_helper(x);
    for (auto& v : x) v = std::conj(v) / static_cast<double>(x.size());
}
