        for (size_t i = left; i < right; ++i)
            for (size_t j = i + 1; j < right; ++j)
                best = std::min(best, dist2(px[i], px[j]));
        return std::sqrt(best);
    }

    size_t mid = left + n / 2;
    double midX = px[mid].x;

    /* build two halves in py order */
    std::vector<Point> pyl, pyr;
    pyl.reserve((mid - left));
    pyr.reserve((right - mid));
    for (auto const& p : py) {
        if (p.x <= midX) pyl.push_back(p);
        else pyr.push_back(p);
    }

    double dl = closest_pair_rec(px, pyl, left, mid);
    double dr = closest_pair_rec(px, pyr, mid, right);
    double d  = std::min(dl, dr);

    /* Build strip */
    std::vector<Point> strip;
    strip.reserve(n);
    double d2 = d * d;
    for (auto const& p : py) {
        if (sqr(p.x - midX) < d2)
            strip.push_back(p);
    }

    /* Compare each point with next <= 7 points */
    for (size_t i = 0; i < strip.size(); ++i) {
        for (size_t j = i + 1;
             j < strip.size() && sqr(strip[j].y - strip[i].y) < d2; ++j) {
            d2 = std::min(d2, dist2(strip[i], strip[j]));
        }
    }
    return std::sqrt(d2);
}

/* Public interface -----------------------------------------------------*/
double closestPair(std::vector<Point> const& points) {
    size_t n = points.size();
    if (n < 2) return 0.0;

    /* ------------------------------------------------------------------
       1. Sort points by x – may be done in parallel (optional)
       2. Build a copy sorted by y to avoid repeated sorting in recursion
       ------------------------------------------------------------------*/
    std::vector<Point> px = points;
    std::vector<Point> py = points;
    #pragma omp parallel sections
    {
        #pragma omp section
        std::sort(px.begin(), px.end());                 // sort by x
        #pragma omp section
        std::sort(py.begin(), py.end(),
                  [](Point const& a, Point const& b){ return a.y < b.y; }); // sort by y
    }

    return closest_pair_rec(px, py, 0, n);
}
