#pragma once
#include <vector>
#include <algorithm>
#include <omp.h>

struct Result {
    int startTime;
    int duration;
    float value;
};

inline bool compareByStart(const Result& a, const Result& b)
{
    return a.startTime < b.startTime;
}

/* Parallel quick‑sort for Result vectors.
   Small vectors (≤ 64 elements) are sorted with the
   serial std::sort.  Larger vectors are partitioned
   recursively using OpenMP tasks so that up to 8
   cores are utilized.  The algorithm mirrors the
   behaviour of std::sort for deterministic output. */
static void parallel_sort(std::vector<Result>& v, std::size_t left, std::size_t right)
{
    if (right - left <= 64) {
        std::sort(v.begin() + left, v.begin() + right, compareByStart);
        return;
    }

    // Lomuto partition
    std::size_t i = left, j = right - 1;
    const Result& pivot = v[right - 1];
    while (i < j) {
        while (i < j && compareByStart(v[i], pivot)) ++i;
        while (i < j && !compareByStart(v[j], pivot)) --j;
        if (i < j) std::swap(v[i], v[j]);
    }
    std::swap(v[i], v[right - 1]);

    // Recurse in parallel
    #pragma omp task shared(v) if (right - left > 1024)
    parallel_sort(v, left, i);

    #pragma omp task shared(v) if (right - left > 1024)
    parallel_sort(v, i + 1, right);
}

void sortByStartTime(std::vector<Result> &results)
{
    if (results.empty()) return;
    #pragma omp parallel
    {
        #pragma omp single
        parallel_sort(results, 0, results.size());
    }
}
