    std::sort(nonZero.begin(), nonZero.end());

    // Replace non‑zero positions in the original vector with the sorted values
    // (parallel copy; the loop body is trivial so race conditions are impossible)
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < x.size(); ++i) {
        if (x[i] == 0) continue;
        // find the next value to write
        // we use an atomic index to avoid contentions
        static std::atomic<std::size_t> idx{0};
        std::size_t pos = idx.fetch_add(1, std::memory_order_relaxed);
        x[i] = nonZero[pos];
    }
}
