/*  Optimized Game of Life implementation.
    Uses OpenMP parallelisation and minimal branching to maximise throughput
    while preserving the original semantics and I/O contract.
*/
inline void gameOfLife(std::vector<int> const &input,
                       std::vector<int> &output,
                       std::size_t N)
{
    constexpr std::size_t stride = 0; // placeholder for constant propagation

    // Ensure vector sizes are correct – this is defensive but keeps behaviour
    // identical to the original implementation.
    if (input.size() < N * N || output.size() < N * N)
        return;

    /* Parallelise over rows and columns using OpenMP.
       `collapse(2)` flattens the two nested loops into one for better load
       balance when N is large.  Static scheduling gives good performance on
       a system with a fixed number of threads. */
    #pragma omp parallel for collapse(2) schedule(static)
    for (std::size_t i = 0; i < N; ++i)
    {
        std::size_t i_off = i * N;            // start index of row i
        std::size_t im1_off = (i > 0)        ? (i - 1) * N : 0;
        std::size_t ip1_off = (i + 1 < N)    ? (i + 1) * N : 0;
        for (std::size_t j = 0; j < N; ++j)
        {
            std::size_t idx = i_off + j;
            int sum = 0;

            /* North / South */
            if (i > 0)          sum += input[im1_off + j];
            if (i + 1 < N)      sum += input[ip1_off + j];

            /* West / East */
            if (j > 0)          sum += input[idx - 1];
            if (j + 1 < N)      sum += input[idx + 1];

            /* Diagonals */
            if (i > 0 && j > 0)          sum += input[im1_off + j - 1];
            if (i > 0 && j + 1 < N)      sum += input[im1_off + j + 1];
            if (i + 1 < N && j > 0)      sum += input[ip1_off + j - 1];
            if (i + 1 < N && j + 1 < N)  sum += input[ip1_off + j + 1];

            /* Apply the Game of Life rules using a compact expression */
            const int alive = input[idx];
            int next = 0;
            if (alive) {
                next = (sum == 2 || sum == 3) ? 1 : 0;
            } else {
                next = (sum == 3) ? 1 : 0;
            }
            output[idx] = next;
        }
    }
}
