// Edge detection kernel
static constexpr int edgeKernel[3][3] = {
    { -1, -1, -1 },
    { -1,  8, -1 },
    { -1, -1, -1 }
};

/*
 * Convolve the edge kernel with a grayscale image.
 * imageIn and imageOut are N×N row-major images.
 * Padding outside the image is treated as zero.
 * Result is clamped to [0,255].
 */
inline void convolveKernel(const std::vector<int> &imageIn,
                           std::vector<int>       &imageOut,
                           std::size_t            N)
{
    // Parallelise the outer loops using OpenMP
    #pragma omp parallel for collapse(2) schedule(static)
    for (std::size_t i = 0; i < N; ++i)
    {
        for (std::size_t j = 0; j < N; ++j)
        {
            int sum = 0;

            // Unrolled 3×3 kernel
            int x0 = i - 1;
            int x1 = i;
            int x2 = i + 1;
            int y0 = j - 1;
            int y1 = j;
            int y2 = j + 1;

            // Row i-1
            if (x0 >= 0 && x0 < N) {
                if (y0 >= 0 && y0 < N) sum += imageIn[x0 * N + y0] * edgeKernel[0][0];
                if (y1 >= 0 && y1 < N) sum += imageIn[x0 * N + y1] * edgeKernel[0][1];
                if (y2 >= 0 && y2 < N) sum += imageIn[x0 * N + y2] * edgeKernel[0][2];
            }
            // Row i
            if (x1 >= 0 && x1 < N) {
                if (y0 >= 0 && y0 < N) sum += imageIn[x1 * N + y0] * edgeKernel[1][0];
                sum += imageIn[x1 * N + y1] * edgeKernel[1][1];  // centre always valid
                if (y2 >= 0 && y2 < N) sum += imageIn[x1 * N + y2] * edgeKernel[1][2];
            }
            // Row i+1
            if (x2 >= 0 && x2 < N) {
                if (y0 >= 0 && y0 < N) sum += imageIn[x2 * N + y0] * edgeKernel[2][0];
                if (y1 >= 0 && y1 < N) sum += imageIn[x2 * N + y1] * edgeKernel[2][1];
                if (y2 >= 0 && y2 < N) sum += imageIn[x2 * N + y2] * edgeKernel[2][2];
            }

            // Clamp the result
            if (sum < 0) {
                imageOut[i * N + j] = 0;
            } else if (sum > 255) {
                imageOut[i * N + j] = 255;
            } else {
                imageOut[i * N + j] = sum;
            }
        }
    }
}
