/* Set every cell's value to 1 if it has exactly one neighbor that's a 1.
   Otherwise set it to 0. The function assumes row‑major order.
   The operation is parallelised over the outer loop for maximum CPU utilisation.
*/
void cellsXOR(std::vector<int> const& input, std::vector<int> &output, size_t N)
{
    const int *data = input.data();
    int *outdata  = output.data();

    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i) {
        const int *row  = data + i * N;
        int       *out  = outdata + i * N;

        // Pointers to the rows above and below (if they exist).
        const int *prev = (i > 0)     ? data + (i - 1) * N : nullptr;
        const int *next = (i + 1 < N) ? data + (i + 1) * N : nullptr;

        for (size_t j = 0; j < N; ++j) {
            int sum = 0;
            if (prev) sum += prev[j];
            if (next) sum += next[j];
            if (j > 0)       sum += row[j - 1];
            if (j + 1 < N)   sum += row[j + 1];

            /* The comparison yields 0 or 1; cast is implicit. */
            out[j] = (sum == 1);
        }
    }
