    // Reserve space and build a vector of (value, original_index) pairs
    std::vector<std::pair<float, std::size_t>> tmp;
    tmp.reserve(n);
    for (std::size_t i = 0; i < n; ++i) tmp.emplace_back(x[i], i);

    // Sort by value only. The pair comparison keeps stable order for equal values.
    std::sort(tmp.begin(), tmp.end(),
              [](const auto& a, const auto& b) { return a.first < b.first; });

    // Parallelised assignment of ranks
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < n; ++i) {
        ranks_[tmp[i].second] = i;
    }
