#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/* Multiply the matrix A by the matrix B. Store the results in the matrix C.
   A is an MxK matrix, B is a KxN matrix, and C is a MxN matrix. The matrices are stored in row‑major.
   Example:
   input: A=[[1, -1, 2], [0, -2, 1]] B=[[4, 1], [-1, 0], [2, 2]]
   output: C=[[9, 5], [4, 2]]   */
inline void gemm(std::vector<double> const& A,
                 std::vector<double> const& B,
                 std::vector<double> &C,
                 size_t M, size_t K, size_t N) {

    /* 1. Basic blocking parameters – tuned for a core that has ~64 KiB of L1‑D cache. */
    constexpr size_t BLOCK_M = 64;   // rows of A / C
    constexpr size_t BLOCK_K = 64;   // inner dimension
    constexpr size_t BLOCK_N = 64;   // columns of B / C

    /* 2. Zero the output matrix before accumulating to avoid incorrect results. */
    #pragma omp parallel for
    for (size_t i = 0; i < M * N; ++i) C[i] = 0.0;

    /* 3. Parallel blocked gemm.  We parallelise over the outer “mega‑blocks” of A and B
       so that each thread works on independent sub‑matrices. */
    #pragma omp parallel for collapse(2) schedule(static)
    for (size_t i0 = 0; i0 < M; i0 += BLOCK_M) {
        for (size_t j0 = 0; j0 < N; j0 += BLOCK_N) {
            for (size_t k0 = 0; k0 < K; k0 += BLOCK_K) {
                /* Compute the micro‑block C[i0..i1-1][j0..j1-1] += A[i0..i1-1][k0..k1-1] * B[k0..k1-1][j0..j1-1] */
                size_t i1 = std::min(i0 + BLOCK_M, M);
                size_t j1 = std::min(j0 + BLOCK_N, N);
                size_t k1 = std::min(k0 + BLOCK_K, K);

                for (size_t i = i0; i < i1; ++i) {
                    for (size_t k = k0; k < k1; ++k) {
                        double aik = A[i * K + k];
                        for (size_t j = j0; j < j1; ++j) {
                            C[i * N + j] += aik * B[k * N + j];
                        }
                    }
                }
            }
        }
    }
}
```
**Explanation of key optimisation points**

1. **Cache blocking** – The loops are broken into blocks (`BLOCK_M`, `BLOCK_K`, `BLOCK_N`) that fit comfortably inside the L1 data cache of a modern x86‑64 core. This reduces the number of cache misses and improves spatial locality.

2. **Parallelism** – The outer two block loops (`i0` and `j0`) are combined with `collapse(2)` to give a fine‑grained parallel workload. `schedule(static)` gives each thread a contiguous strip of work, which keeps thread migration overhead low.

3. **Explicit zeroing** – The output matrix is zeroed in a separate parallel loop before accumulation, ensuring no accidental dependence on stale data.

4. **Loop ordering** – The innermost loop iterates over `j` (columns of `C`/`B`) after `k` to keep the vector index `C[i * N + j]` and `B[k * N + j]` contiguous, improving prefetching.

All semantics match the original reference implementation, and the function signature remains unchanged.

