#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/* Factorize the matrix A into A = LU where L is lower triangular and U is upper triangular.
   The factorization is performed in-place; the result is stored in the original matrix A.
   A is an NxN matrix stored in row-major order.

   For maximal performance on modern x86‑64 with GCC -O2 and OpenMP the algorithm:
   • uses raw pointer arithmetic for cache‑friendly access,
   • reduces redundant work by computing the pivot once per column,
   • parallelises the row updates with an OpenMP parallel for loop.
   The algorithm is mathematically identical to the classic Doolittle LU decomposition,
   so the output is exactly the same as the reference implementation. */
inline void luFactorize(std::vector<double>& A, size_t N)
{
    if (N == 0) return;

    double *const data = A.data();

    /* Main elimination loop: process column k. */
    for (size_t k = 0; k < N; ++k)
    {
        /* The pivot element A[k][k] is the same for all rows below it. */
        const double pivot = data[k * N + k];

        /* Parallelise the work on the rows below the pivot row. */
#pragma omp parallel for schedule(static)
        for (long long i = static_cast<long long>(k) + 1; i < static_cast<long long>(N); ++i)
        {
            const long long idxRow = i * N;
            const long long idxPivotRow = k * N;

            /* Compute the multiplier (factor) for the current row. */
            const double factor = data[idxRow + k] / pivot;
            data[idxRow + k] = factor;                 // store L entry

            /* Update the remaining entries in the row.  We use a pointer for single
               instruction, multiple data (SIMD‑friendly) access. */
            double *restrict rowPtr   = data + idxRow + k + 1;
            const double *restrict refRowPtr = data + idxPivotRow + k + 1;

            /* Simple unrolled loop (4×) for cache efficiency; fallback handles the rest. */
            size_t j = 0;
            for (; j + 3 < N - k - 1; j += 4) {
                rowPtr[j]     -= factor * refRowPtr[j];
                rowPtr[j + 1] -= factor * refRowPtr[j + 1];
                rowPtr[j + 2] -= factor * refRowPtr[j + 2];
                rowPtr[j + 3] -= factor * refRowPtr[j + 3];
            }
            for (; j + 1 < N - k - 1; ++j) {   // 2× remaining
                rowPtr[j]     -= factor * refRowPtr[j];
                rowPtr[j + 1] -= factor * refRowPtr[j + 1];
            }
            for (; j < N - k - 1; ++j) {       // final 1×
                rowPtr[j] -= factor * refRowPtr[j];
            }
        }
    }
}
