#pragma once
#include <vector>
#include <cstddef>
#include <cstdint>
#include <immintrin.h>

/* Return the index of the first even number in the vector x.
   Examples:
   input: [7, 3, 9, 5, 5, 7, 2, 9, 12, 11]
   output: 6
   input: [3, 8, 9, 9, 3, 4, 8, 6]
   output: 1
*/
inline std::size_t findFirstEven(const std::vector<int>& x) {
    const std::size_t n = x.size();
    const int* data = x.data();

    std::size_t i = 0;

    /* SIMD warm‑up: check 8 ints at a time */
    const std::size_t chunk = 8;
    for (; i + chunk <= n; i += chunk) {
        __m256i v = _mm256_loadu_si256(reinterpret_cast<const __m256i*>(data + i));

        /* mask of even numbers: (x & 1) == 0  ->  ~(v & 1) */
        __m256i mask = _mm256_andnot_si256(_mm256_set1_epi32(1), v);

        /* generate a 8‑bit mask where bit k == 1 if element k is even */
        // Convert to a single byte mask
        const __m128i low = _mm256_castsi256_si128(v);
        const __m128i high = _mm256_extractf128_si256(v, 1);

        // Count trailing zeros after shifting by 1 and converting to mask
        int words[2] = { _mm_movemask_epi8(_mm_cmpeq_epi32(low, low)), 
                         _mm_movemask_epi8(_mm_cmpeq_epi32(high, high)) };

        // Build a bitmask of even positions
        unsigned long long evenMask = 0;
        for (int k = 0; k < 8; ++k) {
            if (!(data[i + k] & 1)) {
                evenMask |= 1ULL << k;
            }
        }

        if (evenMask) {
            // Find first set bit
            std::size_t offset = __builtin_ctzll(evenMask);
            return i + offset;
        }
    }

    /* Remaining elements */
    for (; i < n; ++i) {
        if ((data[i] & 1) == 0) {
            return i;
        }
    }
    return n;
}
